final:
module RefModule (
    input clk,
    input rst,
    output reg [2:0] gray
);
    reg [2:0] binary;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            binary <= 3'b000;
        else
            binary <= binary + 1;
    end

    always @(binary) begin
        gray = binary ^ (binary >> 1);
    end
endmodule
